    func getWiFiFingerprint() -> [String: Double] {
        // Get the list of nearby Wi-Fi networks
        let networks = locationManager.getWiFiNetworks()

        // Create a dictionary to store the Wi-Fi fingerprint
        var fingerprint = [String: Double]()

        // Iterate over the list of Wi-Fi networks
        for network in networks {
            // Get the signal strength of the network
            let signalStrength = network.signalStrength

            // Add the signal strength to the fingerprint dictionary
            fingerprint[network.name] = signalStrength
        }

        return fingerprint
    }
}
